namespace Tests;

internal static class IDataServiceServerExtensions
{
    internal static IEndpointRouteBuilder MapIDataServiceEndpoints(
        this IEndpointRouteBuilder endpoints)
    {
        var group = endpoints.MapGroup("/api/functions/data");

        group.MapPost("/SubmitDataAsync",
            async ([FromBody] SubmitDataAsyncRequest request, IDataService service) =>
            {
                var result = await service.SubmitDataAsync(request.Value);
                return Results.Ok(result);
            })
            .WithName("IDataService_SubmitDataAsync")
            .WithTags("DataService")
            .Produces<string>(StatusCodes.Status200OK)
            .ProducesProblem(StatusCodes.Status500InternalServerError)
            .AddEndpointFilter<global::MyApp.Services.FirstFilter>()
            .AddEndpointFilter<global::MyApp.Services.SecondFilter>();

        return endpoints;
    }

    private record SubmitDataAsyncRequest(string Value);
}
